import * as React from "react"

import "../styles/car.css"

import Header from "../components/header"
import Footer from "../components/footer"
import backgroundImage from "../images/background.jpg"
import carHeader from "../images/car_header.jpeg"




import { Container, Card } from "react-bootstrap";



export default function car() {
  return (
    <>
      <Header />

      <div
        className="bg-image"
        style={{
          backgroundImage: `url(${backgroundImage})`,
        }}
      />
      <Container fluid="md" className="py-5">
        <Card className="shadow-sm bg-light  w-100">
          <Card.Body> 
            <img
                className=""
                src={carHeader}
                alt={"痛車"}
                />
              <h4 className="text-start">ENG DEPT. ZN6 -Yuuka Hayase ver.-</h4>
              <p className="text-start">
                「条件はクリアされました。私たちは今日この瞬間を絆と定義し、証明することになるでしょう。」
                <br /><br />

                イラスト : 柊奈さん(
                <a
                    href="https://x.com/F_ijuusya"
                    target="_blank"
                    rel="noopener noreferrer"
                >
                    @F_ijuusya
                </a>
                )<br />

                デザイン＆施工 : street graphixさん(
                <a
                    href="https://x.com/street_graphix"
                    target="_blank"
                    rel="noopener noreferrer"
                >
                    @street_graphix
                </a>
                )
            </p>
              <p className="text-start">
                Car : ZN6 GT Limited<br/>
                Wheel : Rays GramLights 57Gainer<br/>
                
              </p>
          </Card.Body>
        </Card>
      </Container>
      <Footer />
    </>
  );
}